const Q_PHYSICS_2020_MODEL_II=[{"id": "objective>Physics>2020 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a fundamental S.I unit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">meter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ampere</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> steradian <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">second</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental S.I units are meter, kilogram, second, ampere, kelvin, mole, and candela. Steradian is not a fundamental S.I unit, it is a derived unit used for solid angle measurement in three-dimensional space.</div>", "topic": "MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}, {"id": "objective>Physics>2020 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boy travels 12km eastward to a point B and then 5km southwards to another point C. Calculate the difference between the magnitude of the displacement of the boy and the distance travelled by him.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0km <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.0km <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.0km <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagramatically <br/>  <img src=\"2020 Model II/phy2102.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> Total distance covered= /OB/ + /BC/=12km + 5km=17km <br/> Displacement will be gotten by vector addition. <br/>  <img src=\"2020 Model II/phy2102s.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> /OC/<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>=/OB/<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + /BC/<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> /OC/<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>=12<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> /OC/<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>=144 + 25 <br/> /OC/<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>=169 <br/> /OC/=13km <br/> The difference= 17km-13km=4km <br/>  <br/>  <br/>  <br/>  <br/>  <br/>  <br/>  </div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2020 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The motion of a body is simple harmonic if the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acceleration is always directed towards a fixed point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">path of motion is a straight line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acceleration is directed towards a fixed and is proportional to its distance from the point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acceleration is constant and directed towards a fixed point</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In SHM, acceleration towards a fixed point like a circular motion. Also, the acceleration is proportional to the displacement or distance from the fixed point unlike circular motion. </div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2020 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Three masses are hanging from a light rod 0.1m long as shown in the figure above. To keep the rod horizontal, the mass of X must be  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0kg</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the rod is a light rod, the weight is negligible. <br/> <img src=\"2020 Model II/phy2104.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> Taking moment about the suspension rope, <br/> ACW=CW <br/> 2(0.25) + 1(0.5)=X(0.5) <br/> 0.5 + 0.5= 0.5X <br/> X=2kg <br/> </div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2020 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ball of mass 100g falls from a height of 5m onto a floor and rebounds to a height of 3m.What energy is lost as a result of impact on the floor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> mass,m=100g=0.1kg <br/> height of fall= 5m <br/> Rebound height=3m <br/> Energy loss=unknown <br/>  <img src=\"2020 Model II/phy2105.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> At the point of impact with the ground, the energy (K.E)=P.E(at h=5m)=mgh,where h=5m. <br/> When it rebounds, parts of this energy is lost,so that the ball cannot reach 5m height again,it can only reach 5m height again,it can only reach h=3m <br/> Energy loss=(0.1 ∗ 10 ∗ 5)-(0.1 ∗ 10 ∗3)=5J -3J=2J</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2020 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A block of mass 50kg is given an initial speed of 5m/s on a rough horizontal floor for 3m before it stops, calculate the co-efficient of kinetic friction between the block and the floor (g=10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.03</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.41</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.67</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given=mass,m=50kg <br/> u=5m/s;distance travelled before it stops=3m <br/> U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span>=unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span></td><td style=\"text-align:center;\">=F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span><hr size=\"1\" />mg---------------*</td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span>→=m(a→) <br/> a→=deceleration or negative acceleration(since we are dealing with frictional force) <br/> Since the ear stops, it means v=0 <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>=u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2as <br/> 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>=5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> +2(a)(3) <br/> -25=6a <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a=</td><td style=\"text-align:center;\">-25<hr size=\"1\" />6</td><td style=\"text-align:center;\">mls<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div></div>", "topic": "FRICTION"}, {"id": "objective>Physics>2020 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lubricants are used in machines to reduce friction </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreases the M.A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the M.A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the V.R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the V.R</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that the velocity ratio (V.R) of a machine is not affected by friction.Lubricants are applied to reduce friction so that less effort will be used to overcome large load, Hence if L≻E, then M.A≻1(increased M.A)</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>2020 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bar of length 3m is subjected to two parallel but opposite forces of 60N at its ends as shown in the diagram above. The couple on the bar is <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90√3Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">360Nm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2020 Model II/phy2108is.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> The vertical component of 60N=60sin30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>=30N <br/> <img src=\"2020 Model II/21082s.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> Couple= 30N ∗ 3m=90Nm   </div>", "topic": "EQUILIBRIUM OF FORCES"}, {"id": "objective>Physics>2020 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The escape velocity of an object from the gravitational field of a planet. <br/> I.increases with the mass of the object. <br/> II.increases with the mass of the planet. <br/> III. is smaller on the moon than on the earth <br/> Which of the above statements is(are) correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I,II and III</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Escape</td><td style=\"text-align:center;\">velocity,V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>=</td><td style=\"text-align:center;\">√2Gm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td></tr></table></div> <br/> Also,V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>= √2g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>/r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>--------------2 <br/> Where m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>,r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>,g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> are the mass,radius of the planet and acceleration due to gravity on the planet respectively. Note that V is independent of the mass of the object.Also, since g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> and r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> are smaller moon,v is smaller on the moon.</div>", "topic": "GRAVITATIONAL FIELD : ESCAPE VELOCITY"}, {"id": "objective>Physics>2020 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The load supported by a spring is increased from 50N to 90N. If the force constant for the spring is 2000Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the additional energy stored in the spring due to the increase in load is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.40J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.90J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.40J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 50N  <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 90N <br/>  K=2000Nm <br/> F=Ke ; e=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">F</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">k</span> <br/>  <br/> e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">50</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2000</span> <br/>  <br/> e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 0.025 <br/>  <br/> e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">90</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2000</span> <br/>  <br/> e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.045 <br/>  <br/> ΔE = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span>K(e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) <br/>  <br/> ΔE =<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> × 2000 × (0.045<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 0.025<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>) <br/>  <br/> ΔE = 1.4J <br/> </div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2020 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When light crosses a boundary between air and water, the following quantity of light remains the same</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Speed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When light crosses a boundary between two different mediums, such as air and water, its speed and wavelength change due to the change in the medium's refractive index. However, the frequency of the light remains the same because it is a property of the light source and is not affected by the medium. Therefore, the frequency of light remains the same when it crosses from air to water.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2020 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A beam of light has a wavelength of 600nm in air. What is the frequency of the light? (c = 3 &#215; 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m/s)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Waveleght = 600nm =0.6 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> <br/> Speed, c= 3 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Frequency=unknown <br/> Recall:velocity=Frequency ∗ wavelenght <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Therefore</td><td style=\"text-align:center;\">Frequency=</td><td style=\"text-align:center;\">velocity<hr size=\"1\" />wavelength</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Frequency=3</td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span><hr size=\"1\" />6</td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span></td></tr></table></div> <br/> F= 5 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz <br/>  <br/> </div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2020 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fixed mass of gas is heated at constant volume so that its celsius temperature is doubled the pressure of the gas</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is halved</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is doubled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is more than doubled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases but is less than doubled</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At constant volume, P ⋉ T (Pressure law) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">(T</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">kelvin) <br/>  <br/> </td></tr></table></div> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>+273</td></tr></table></div> <br/>  <br/>  <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>( in celsius) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td></tr></table></div> <br/>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  =(2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273)P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />(T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273) <br/> </td></tr></table></div> <br/> The pressure increases but is less than doubled <br/>  <br/>  <br/>  <br/>  <br/>  <br/>  <br/> </div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2020 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A person in a room feels cooler under a rotating fan because the fan </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lowers the room temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases the rate of evaporation from the skin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduces the relative humidity in the room</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blows cooler air to the skin</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The skin feels cooler as the rate of evaporation from its surface increases. The room temperature and relative humidity do change appreciably, and the blown air is at room temperature</div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>2020 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object floats in water with 90% of its volume submerged and in a liquid L with 60% of its volume submerged. The relative density of L is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.54</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.67</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.50</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let V=volume of object <br/> d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span>=density of water <br/> d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span>=density of liquid L <br/> Mass of water displaced= 0.9V ∗ d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span>=mass of object <br/> Mass of L displaced= 0.6V ∗ d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>= mass of object <br/> Recall <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>=</td><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span><hr size=\"1\" />d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span></td></tr></table></div> <br/> ⇒0.9V d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span>= 0.6Vd<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span><hr size=\"1\" />d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.9v<hr size=\"1\" />0.6v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.50</td></tr></table></div></div>", "topic": "LIQUIDS AT REST : ARCHIMEDE’S PRINCIPLE"}, {"id": "objective>Physics>2020 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A closed organ pipe and an open organ pipe emit notes of the same pitch. The ratio of the length of the air column in the closed pipe to that <br/> of the air column in the closed pipe to that of the open pipe is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<hr size=\"1\" />4 <br/> </td></tr></table></div> <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = λ/2)(for open pipe) <br/> 2L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 4L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div></div>", "topic": "CHARACTERISTICS OF SOUND WAVES : FREQUENCY OF A NOTE EMITTED BY AIR COLUMNS"}, {"id": "objective>Physics>2020 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If ohm's law is written as I = KV, the proportionality constant K is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">resistance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">conductance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resistivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conductivity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> V=IR is the common Ohm's law equation that you know <br/> ⇒ I = V/R <br/> I = I/R ∗ V <br/> K = 1/R <br/> k= conductance(inverse resistance)</div>", "topic": "CURRENT ELECTRICITY : OHM’S LAW"}, {"id": "objective>Physics>2020 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a wire of a specified material, which of the following will give you the lowest resistance in a circuit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A short thin wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A long, thin wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A short, thick wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A long, thick wire</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The resistance of a wire is given by the formula R = ρL/A, where R is the resistance, ρ is the resistivity of the material, L is the length of the wire, and A is the cross-sectional area of the wire. From this formula, we can see that the resistance decreases as the length of the wire decreases and the cross-sectional area increases. Therefore, a short, thick wire will have the lowest resistance.</div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2020 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following may produce a virtual image? <br/> i. convex mirror  <br/> ii. concave mirror  <br/> iii. convex lens  <br/> iv. concave lens</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i,ii and iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i,ii,iii and iv</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A virtual image may be produced by any of the mirrors or lenses depending on the position of the object. However, real images can be produced only by a concave mirrors and convex lens </div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES~~REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2020 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A change in temperature of 45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C is equivalent to a change in temperature on the kelvin scale of   </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">81k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">318k</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The change in temperature of 45k. This is because both the scale(Celsius and kelvin) have the same divisions.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2020 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A yellow liquid in a green, transparent bottle will appear</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The green bottle absorbs all colours except green. Yellow is composed of red and green. Hence the bottle absorbs the red and transmits green</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2020 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 12v battery of internal resistance 0.1Ω is connected across a lamp of resistance R. If a current of 10A flows through the circuit, the value of R is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.9Ω <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0Ω <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.1Ω <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2Ω <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> e.m.f, E= 12v <br/> internal resistance, r=0.1Ω <br/> load, R=R <br/> current, I= 10A <br/> Recall: E= I(R+r) <br/> ⇒12=10(R + 0.1) <br/>      12=10R + 1 <br/>       11= 10R  <br/>      <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R=</td><td style=\"text-align:center;\">11<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.1Ω <br/> </td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY : RESISTANCE"}, {"id": "objective>Physics>2020 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On a hot and sunny day, the inside of a car with the glass windows rolled up is hotter if the upholstery is black than if it is made of a bright and sunny material because a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bright and sunny surface is better reflector of heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bright and sunny surface is a better radiator of heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black surface is a better conductor of heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black surface has a lower thermal capacity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The color of an object can affect how much sunlight it absorbs or reflects. Darker colors, like black, absorb more sunlight and therefore heat up more than lighter colors, which reflect more sunlight. Therefore, if the upholstery is black, it will absorb more heat and make the inside of the car hotter on a sunny day.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2020 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above shows an object OX placed in front of a convex mirror. As the object is moved towards P, its image, which is located between P and F </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">moves the right and becomes smaller </div>", "<div style=\"font-family:Cambria;font-size:17px;\">moves to the right and become larger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moves to the left and becomes smaller </div>", "<div style=\"font-family:Cambria;font-size:17px;\">moves to the left and becomes larger</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This question is easily solved by assigning arbitrary values to u and evaluating v from the mirror equation. <br/> 1/v = 1/f - 1/u <br/> Thus if u= 2f <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-1<hr size=\"1\" />f</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />2f <br/> </td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">⇒1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-3<hr size=\"1\" />2f</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-2f<hr size=\"1\" />3 <br/> </td></tr></table></div><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Magnification=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2f/3<hr size=\"1\" />2f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2f<hr size=\"1\" />3</td><td style=\"text-align:center;\">∗1<hr size=\"1\" />2f</td><td style=\"text-align:center;\">=1<hr size=\"1\" />3</td></tr></table></div> <br/> After the object is mioved to u=f, for instance  <br/> 1/v= -1/f - 1/f = -2/f <br/> or v= -f/2 (i.e, the image is now closer to the mirror) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Magnification</td><td style=\"text-align:center;\">=f/2<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(image</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\">now</td><td style=\"text-align:center;\">larger) <br/> </td></tr></table></div> N.B: the question can also be answered correctly by sketching the ray diagrams for two positions of the object</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>2020 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are parts of the eye  <br/> I. Retina  <br/> II. Pupil <br/> III. Iris <br/> The correct equivalent in the camera in the same order are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Diaphragm, Aperture,Film</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Film,Diaphram,Aperture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aperture,Diaphragm,Film</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Film,Aperture,Diaphragm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">-Retina is similar to film <br/> -Pupil is similar to aperture <br/> -Iris is similar to diaphragm.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2020 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium is sometimes used as the leaf of an electroscope because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is a light material </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a good conductor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a good insulator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can be converted into thin sheets</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium is used as the leaf of an electroscope because it is a good conductor. An electroscope is a device used to detect and measure electric charge, and it works by allowing charges to flow freely along its surface. As a good conductor, aluminium allows this charge flow to happen easily.</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2020 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capacitors are used in the induction coil to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dissipate energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent electric sparks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent distortion of electric fields </div>", "<div style=\"font-family:Cambria;font-size:17px;\">control circuits</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capacitors are used in storing charges rather than dissipation of charges. capacitors are used in induction coil prevent initial sparks that can wear the contact. <br/> Capacitors are used to power pack circuits for obtaining D.C voltages from A.C supply (filtering)</div>", "topic": "CAPACITORS"}, {"id": "objective>Physics>2020 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of powder magnet into solid blocks by the application of heat and great pressure is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hardening</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sintering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluxing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetization</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of powered magnetic materials into a solid block under great pressure and heat is called sintering</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2020 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The lead-acid accumulator consist of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lead as the positive electrode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead oxide as the negative electrode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrochloric acid as the electrolyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetraoxosulphate(vi) acid as the electrolyte</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The positive pole is lead peroxide(PbO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) ; the negative pole is lead. The electrolyte is H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/> a battery with lead electrodes with dilute tetraoxosulphate (VI) acid as the electrolyte; each cell generates about 2 volts</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2020 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the diagram below, AB represents a potentiometer wire of length 1m and resistance 4Ω. A cell of e.m.f 2v provides a steady current in the wire. If the cell with e.m.f 1.1v gives no current when the jockey is at point P, calculate the value of the balanced length AP( neglect the internal resistance of the 2v cell)  <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.875cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">68.75cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.432cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.621cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total resistance in the circuit= 1Ω + 4Ω= 5Ω <br/> E=2v; <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I=E<hr size=\"1\" />R+r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R</td><td style=\"text-align:center;\"></td></tr></table></div> (for negligible, r) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">⇒I=</td><td style=\"text-align:center;\">2<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.4A</td></tr></table></div> <br/> E.m.f across the wire AB= V=IR = 0.4 ∗ 4=1.6V <br/> Hence, E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=1.6v, when L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=1m  <br/>              E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=1.1v, when L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=? <br/> Recall: E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/ E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> =  L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/ L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> =  E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/ E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1∗1.1/1.6 = 0.6875m≏ 68.75cm</div>", "topic": "CURRENT ELECTRICITY : POTENTIOMETER"}, {"id": "objective>Physics>2020 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A lamp is connected across a battery. A piece of low conductivity wire is now connected in series with it. The lamp will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glow brighter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">glow dimmer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain unaffected</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quickly burn out</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The low conductivity wire has a high resistance.Since this is connected in series with the lamp. Current through the circuit is reduced (I=V/R) and the lamp glows dimmer</div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2020 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Upon starting a car, a current of 125 A is drawn from the 12 V battery and p.d across the terminals drops to 8 V. The internal resistance of the battery is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.0096Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.064Ω <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.032Ω <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.016Ω <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given  <br/> E=12V <br/> V=8v <br/> I= 125A <br/> r=? <br/> Recall: E=V+Ir <br/> 12=8 + 125r <br/> 4= 125r <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">r=</td><td style=\"text-align:center;\">4<hr size=\"1\" />125</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.032Ω <br/> </td></tr></table></div></div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2020 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the circuit diagram above, the key K is initially open.When the key is closed, the reading on the ammeter (A) </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remains unaffected </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease to zero because of short circuit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases to one-third of its initial value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases to thrice its initial value</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two 4Ω resistors in parallel have an effective resistance of 2Ω. With the key open, the total resistance of the circuit is 2+4=6Ω and <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I=</td><td style=\"text-align:center;\">V<hr size=\"1\" />R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />6</td><td style=\"text-align:center;\">=2A <br/> </td></tr></table></div> with the key closed, the single 4Ω resistor is effectively shut out and the circuit has an effective resistance of 2Ω. Thus <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I=</td><td style=\"text-align:center;\">12<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3x</td><td style=\"text-align:center;\"></td></tr></table></div>original current <br/> </div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2020 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 1.2kw immersion heater is connected to a voltage supply of 240v. The resistance of the heater element and the current drawn by the heater are, respectively </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5Ω, 48A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1200Ω, 0.2A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48Ω, 5A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.2Ω, 1200A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Power rating,P=1.2W= 1200W <br/> Voltage, V=240V <br/> Resistance, R =unknown <br/> Current, I= unknown. <br/> Recall: P=V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/R <br/> 1200= (240)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/R; <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R=</td><td style=\"text-align:center;\">240∗240<hr size=\"1\" />1200</td></tr></table></div> =48Ω <br/> Recall; V=IR <br/> 240=I ∗ 48 <br/> I= 5.0A <br/> (R,I)= 48Ω,5.0A <br/>  <br/> </div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2020 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A freely suspended magnetic needle makes an angle of 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> with the horizontal at a location X of the earth's surface. Which of the statement is(are) correct about X <br/> I. X is located on the magnetic equator <br/> II. X is located on the magnetic pole <br/> III. The declination at x is zero <br/> IV. The geographical and the magnetic meridians coincide at point X</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I,III and IV only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The angle of dip is zero on the magnetic equator and 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> at the magnetic poles.(This has nothing to do with the declination which is the angle between the magnetic and geographic meridians)</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : EARTH’S MAGNETIC FIELD"}, {"id": "objective>Physics>2020 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A nucleus of <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H decays to form a nucleus of   <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He. This is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an alpha decay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a beta decay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a gamma decay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a neutron decay</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a beta decay since the atomic number of the product is one higher than that of the reactant <br/> ⇒<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H→<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>β</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>2020 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metallic surface is exposed in turn to green,red and violet lights. The maximum kinetic energy of photoelectrons ejected from the surface increases in the order </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">green,red,violet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">violet,green,red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">red,green,violet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">violet,red,green</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: E=hf - ϕ <br/> Hence, the highest frequency radiation gives the most energetic photoelectrons. In the light spectrum (ROYGBIV), red has the lowest frequency and violet has the highest. <br/> The maximum K.E of the photoelectrons thus increases in the order;red,green and violet</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC AND PHOTOELECTRIC EMISSIONS"}, {"id": "objective>Physics>2020 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A diode is not used for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Regulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amplification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Detection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Instrument protection</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A diode is a two-terminal electronic component that conducts current primarily in one direction. It has low resistance in one direction, and high resistance in the other. Diodes are commonly used for regulation (as in voltage regulation), detection (as in radio demodulation), and instrument protection (as in surge protection). However, they are not typically used for amplification. Amplification, the increase of the power of a signal, is usually achieved using devices like transistors or operational amplifiers.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2020 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an a.c circuit, a voltage supply of 20V r.m.s is connected to a 5Ω resistor. Find the peak value of the current <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.50A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.66A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.00A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vrms= 20volts <br/> R=5Ω <br/> Recall;V=IR <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I=</td><td style=\"text-align:center;\">V<hr size=\"1\" />R</td></tr></table></div> <br/> ⇒Irms = Vrms/R = 20/5 = 4A <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Peak</td><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">maximum</td><td style=\"text-align:center;\">current=</td><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Im;</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">Irms</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />√2</td></tr></table></div> <br/> ⇒I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> =√2 ∗ I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rms</span> =√2 ∗ 4 =5.66A <br/> </div>", "topic": "SIMPLE A. C. CIRCUITS : PEAK AND R.M.S. VALUES"}, {"id": "objective>Physics>2020 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A band of 500 rectangular loops of wire of area 20cm by 20cm, encloses a region of magnetic field which changes from 1.07 to 0.47 within 5 seconds, calculate the induced e.m.f</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.60v</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24.00v</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.24v</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.40v</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Number of loops, H= 500 <br/> Area, A= 20∗20∗10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> ∆B= dB = (1-0.4) = 0.6T <br/> t= seconds, E=? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall</td><td style=\"text-align:center;\">E=</td><td style=\"text-align:center;\">Nd<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span><hr size=\"1\" />d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">t</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">NAdB<hr size=\"1\" />dt</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500∗20∗20∗10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>∗0.6<hr size=\"1\" />5</td></tr></table></div>=2.4v</div>", "topic": "ELECTROMAGNETIC INDUCTION"}];
